  1	import * as React from 'react';
  2	import { Chart, ChartBar, ChartStack, ChartAxis, ChartTooltip, ChartLegend } from '@patternfly/react-charts';
  3	
  4	import { PFColors } from '../../components/Pf/PfColors';
  5	import { SUMMARY_PANEL_CHART_WIDTH } from '../../types/Graph';
  6	import { RichDataPoint, VCLines } from 'types/VictoryChartInfo';
  7	import { addLegendEvent, VCEvent } from 'utils/VictoryEvents';
  8	import cssVariables from 'styles/variables.module.scss';
  9	
 10	export const legendHeight = 25;
 11	export const legendTopMargin = 20;
 12	
 13	type Props = {
 14	  baseName: string;
 15	  series: VCLines<RichDataPoint>;
 16	  height: number;
 17	  xLabelsWidth: number;
 18	};
 19	
 20	type State = {
 21	  hiddenSeries: Set<number>;
 22	};
 23	
 24	export class RateChart extends React.Component<Props, State> {
 25	  constructor(props: Props) {
 26	    super(props);
 27	    this.state = { hiddenSeries: new Set() };
 28	  }
 29	
 30	  render() {
 31	    const singleBar = this.props.series[0].datapoints.length === 1;
 32	    let height = this.props.height + legendTopMargin + legendHeight;
 33	    const padding = {
 34	      top: singleBar ? 10 : 15,
 35	      left: 5 + this.props.xLabelsWidth,
 36	      bottom: 10 + legendTopMargin + legendHeight,
 37	      right: 10
 38	    };
 39	    const events: VCEvent[] = [];
 40	    this.props.series.forEach((_, idx) => {
 41	      addLegendEvent(events, {
 42	        legendName: this.props.baseName + '-legend',
 43	        idx: idx,
 44	        serieID: [this.props.baseName + '-bars-' + idx],
 45	        onClick: __ => {
 46	          // Same event can be fired for several targets, so make sure we only apply it once
 47	          if (!this.state.hiddenSeries.delete(idx)) {
 48	            // Was not already hidden => add to set
 49	            this.state.hiddenSeries.add(idx);
 50	          }
 51	          this.setState({ hiddenSeries: new Set(this.state.hiddenSeries) });
 52	          return null;
 53	        },
 54	        onMouseOver: props => {
 55	          return {
 56	            style: { ...props.style, strokeWidth: 4, fillOpacity: 0.5 }
 57	          };
 58	        }
 59	      });
 60	    });
 61	
 62	    const fontSize = cssVariables.kialiFontSize;
 63	    const fontSizePx = cssVariables.kialiFontSizePx;
 64	
 65	    const horizontalAxisStyle = { tickLabels: { fill: PFColors.Color100, fontSize: fontSize, padding: 3 } };
 66	    const verticalAxisStyle = singleBar
 67	      ? { tickLabels: { fill: 'none', fontSize: fontSize } }
 68	      : { tickLabels: { fill: PFColors.Color100, fontSize: fontSize, padding: 2 } };
 69	
 70	    return (
 71	      <Chart
 72	        height={height}
 73	        width={SUMMARY_PANEL_CHART_WIDTH}
 74	        padding={padding}
 75	        domainPadding={{ x: singleBar ? [15, 15] : [30, 25] }}
 76	        domain={{ y: [0, 100] }}
 77	        events={events as any[]}
 78	      >
 79	        <ChartStack
 80	          colorScale={this.props.series
 81	            .filter((_, idx) => !this.state.hiddenSeries.has(idx))
 82	            .map(d => d.color || 'black')}
 83	          horizontal={true}
 84	        >
 85	          {this.props.series.map((datum, idx) => {
 86	            if (this.state.hiddenSeries.has(idx)) {
 87	              return undefined;
 88	            }
 89	            return (
 90	              <ChartBar
 91	                key={this.props.baseName + '-bars-' + idx}
 92	                name={this.props.baseName + '-bars-' + idx}
 93	                data={datum.datapoints.map(dp => {
 94	                  return {
 95	                    ...dp,
 96	                    label: `${dp.name}: ${dp.y.toFixed(2)} %`
 97	                  };
 98	                })}
 99	                barWidth={10}
100	                labelComponent={
101	                  <ChartTooltip constrainToVisibleArea={true} flyoutStyle={{ stroke: 'none', fillOpacity: 0.6 }} />
102	                }
103	              />
104	            );
105	          })}
106	        </ChartStack>
107	        <ChartAxis style={verticalAxisStyle} />
108	        <ChartAxis
109	          style={horizontalAxisStyle}
110	          dependentAxis={true}
111	          showGrid={true}
112	          crossAxis={false}
113	          tickValues={[0, 25, 50, 75, 100]}
114	        />
115	        <ChartLegend
116	          style={{ labels: { fill: PFColors.Color100, fontSize: Number(fontSizePx) } }}
117	          name={this.props.baseName + '-legend'}
118	          data={this.props.series.map((s, idx) => {
119	            if (this.state.hiddenSeries.has(idx)) {
120	              return { ...s.legendItem, symbol: { fill: PFColors.Color200 } };
121	            }
122	            return s.legendItem;
123	          })}
124	          x={this.props.xLabelsWidth}
125	          y={height - legendHeight}
126	          height={legendHeight}
127	          width={SUMMARY_PANEL_CHART_WIDTH}
128	          gutter={14}
129	          symbolSpacer={8}
130	        />
131	      </Chart>
132	    );
133	  }
134	}
135	
136	export const renderRateChartHttp = (
137	  percent2xx: number,
138	  percent3xx: number,
139	  percent4xx: number,
140	  percent5xx: number,
141	  percentNR: number
142	) => {
143	  const vcLines: VCLines<RichDataPoint> = [
144	    { name: 'OK', x: 'rate', y: percent2xx, color: PFColors.Success },
145	    { name: '3xx', x: 'rate', y: percent3xx, color: PFColors.Info },
146	    { name: '4xx', x: 'rate', y: percent4xx, color: PFColors.ChartWarning }, // 4xx client error, use close but distinct color
147	    { name: '5xx', x: 'rate', y: percent5xx, color: PFColors.ChartDanger },
148	    { name: 'No Response', x: 'rate', y: percentNR, color: PFColors.ChartOther } // No Response, just use black
149	  ].map(dp => {
150	    return {
151	      datapoints: [dp],
152	      color: dp.color,
153	      legendItem: {
154	        name: dp.name === 'No Response' ? 'NR' : dp.name,
155	        symbol: { fill: dp.color }
156	      }
157	    };
158	  });
159	  return <RateChart baseName={'rate-http'} height={80} xLabelsWidth={0} series={vcLines} />;
160	};
161	
162	export const renderRateChartGrpc = (percentOK: number, percentErr: number) => {
163	  const vcLines: VCLines<RichDataPoint> = [
164	    { name: 'OK', x: 'rate', y: percentOK, color: PFColors.Success },
165	    { name: 'Err', x: 'rate', y: percentErr, color: PFColors.Danger }
166	  ].map(dp => {
167	    return {
168	      datapoints: [dp],
169	      color: dp.color,
170	      legendItem: {
171	        name: dp.name,
172	        symbol: { fill: dp.color }
173	      }
174	    };
175	  });
176	  return <RateChart baseName={'rate-grpc'} height={80} xLabelsWidth={0} series={vcLines} />;
177	};
178	
179	export const renderInOutRateChartHttp = (
180	  percent2xxIn: number,
181	  percent3xxIn: number,
182	  percent4xxIn: number,
183	  percent5xxIn: number,
184	  percentNRIn: number,
185	  percent2xxOut: number,
186	  percent3xxOut: number,
187	  percent4xxOut: number,
188	  percent5xxOut: number,
189	  percentNROut: number
190	) => {
191	  const vcLines: VCLines<RichDataPoint> = [
192	    {
193	      name: 'OK',
194	      dp: [
195	        { x: 'In', y: percent2xxIn },
196	        { x: 'Out', y: percent2xxOut }
197	      ],
198	      color: PFColors.Success
199	    },
200	    {
201	      name: '3xx',
202	      dp: [
203	        { x: 'In', y: percent3xxIn },
204	        { x: 'Out', y: percent3xxOut }
205	      ],
206	      color: PFColors.Info
207	    },
208	    {
209	      name: '4xx',
210	      dp: [
211	        { x: 'In', y: percent4xxIn },
212	        { x: 'Out', y: percent4xxOut }
213	      ],
214	      color: PFColors.ChartWarning
215	    }, // 4xx client error, use close but distinct color
216	    {
217	      name: '5xx',
218	      dp: [
219	        { x: 'In', y: percent5xxIn },
220	        { x: 'Out', y: percent5xxOut }
221	      ],
222	      color: PFColors.ChartDanger
223	    },
224	    {
225	      name: 'No Response',
226	      dp: [
227	        { x: 'In', y: percentNRIn },
228	        { x: 'Out', y: percentNROut }
229	      ],
230	      color: PFColors.ChartOther
231	    } // No Response error, just use black
232	  ].map(line => {
233	    return {
234	      datapoints: line.dp.map(dp => ({
235	        name: line.name,
236	        color: line.color,
237	        ...dp
238	      })),
239	      color: line.color,
240	      legendItem: {
241	        name: line.name === 'No Response' ? 'NR' : line.name,
242	        symbol: { fill: line.color }
243	      }
244	    };
245	  });
246	  return <RateChart baseName={'in-out-rate-http'} height={80} xLabelsWidth={25} series={vcLines} />;
247	};
